module UART_TX_FSM(Data_Valid, PAR_EN, ser_done, CLK, RST, ser_en,
     mux_sel, busy, DFT_in, DFT_sdi, DFT_sen, DFT_sdo);
  input Data_Valid, PAR_EN, ser_done, CLK, RST, DFT_in, DFT_sdi,
       DFT_sen;
  output ser_en, busy, DFT_sdo;
  output [1:0] mux_sel;
  wire Data_Valid, PAR_EN, ser_done, CLK, RST, DFT_in, DFT_sdi, DFT_sen;
  wire ser_en, busy, DFT_sdo;
  wire [1:0] mux_sel;
  wire [2:0] current_state;
  wire n_0, n_1, n_2, n_3, n_4, n_5, n_6, n_8;
  wire n_18, n_21;
  NOR2BX1 g222(.AN (n_18), .B (DFT_sdo), .Y (busy));
  NOR2BX1 g223(.AN (current_state[1]), .B (DFT_sdo), .Y (mux_sel[1]));
  NOR2BX1 g224(.AN (current_state[0]), .B (DFT_sdo), .Y (ser_en));
  OR2X1 g225(.A (current_state[0]), .B (current_state[1]), .Y (n_18));
  SDFFRHQX1 \current_state_reg[0] (.RN (n_3), .CK (CLK), .D (n_8), .SI
       (DFT_sdi), .SE (DFT_sen), .Q (current_state[0]));
  OAI22X1 g284(.A0 (DFT_sdo), .A1 (n_21), .B0 (ser_done), .B1 (n_4), .Y
       (n_8));
  SDFFRHQX1 \current_state_reg[2] (.RN (n_3), .CK (CLK), .D (n_6), .SI
       (current_state[1]), .SE (DFT_sen), .Q (DFT_sdo));
  AOI21X1 g287(.A0 (current_state[0]), .A1 (n_5), .B0 (n_2), .Y (n_6));
  SDFFRHQX1 \current_state_reg[1] (.RN (n_3), .CK (CLK), .D (busy), .SI
       (current_state[0]), .SE (DFT_sen), .Q (current_state[1]));
  NAND2BX1 g289(.AN (PAR_EN), .B (ser_done), .Y (n_5));
  NAND2X1 g290(.A (current_state[0]), .B (mux_sel[1]), .Y (n_4));
  OR2X1 g291(.A (DFT_in), .B (RST), .Y (n_3));
  INVX1 g292(.A (mux_sel[1]), .Y (n_2));
  INVX1 g293(.A (n_18), .Y (n_1));
  INVX1 g294(.A (current_state[1]), .Y (n_0));
  AOI22X1 g2(.A0 (n_0), .A1 (n_18), .B0 (n_1), .B1 (Data_Valid), .Y
       (n_21));
endmodule

