  XNOR2X1 g260(.A (n_14), .B (n_15), .Y (n_16));
  XNOR2X1 g261(.A (n_12), .B (n_10), .Y (n_15));
  XNOR2X1 g262(.A (n_13), .B (n_11), .Y (n_14));
  XNOR2X1 g263(.A (parallel_data[3]), .B (parallel_data[5]), .Y (n_13));
  XNOR2X1 g264(.A (parallel_data[0]), .B (DFT_sdo), .Y (n_12));
