  XNOR2X1 g266(.A (parallel_data[2]), .B (parallel_data[4]), .Y (n_10));
  SDFFRHQX1 \parallel_data_reg[2] (.RN (n_1), .CK (CLK), .D (n_7), .SI
       (parallel_data[1]), .SE (DFT_sen), .Q (parallel_data[2]));
  SDFFRHQX1 \parallel_data_reg[1] (.RN (n_1), .CK (CLK), .D (n_2), .SI
       (parallel_data[0]), .SE (DFT_sen), .Q (parallel_data[1]));
  SDFFRHQX1 \parallel_data_reg[0] (.RN (n_1), .CK (CLK), .D (n_4), .SI
       (DFT_sdi), .SE (DFT_sen), .Q (parallel_data[0]));
  SDFFRHQX1 \parallel_data_reg[3] (.RN (n_1), .CK (CLK), .D (n_8), .SI
       (parallel_data[2]), .SE (DFT_sen), .Q (parallel_data[3]));
  SDFFRHQX1 \parallel_data_reg[6] (.RN (n_1), .CK (CLK), .D (n_3), .SI
       (parallel_data[5]), .SE (DFT_sen), .Q (parallel_data[6]));
  SDFFRHQX1 \parallel_data_reg[5] (.RN (n_1), .CK (CLK), .D (n_6), .SI
       (parallel_data[4]), .SE (DFT_sen), .Q (parallel_data[5]));
  SDFFRHQX1 \parallel_data_reg[4] (.RN (n_1), .CK (CLK), .D (n_9), .SI
       (parallel_data[3]), .SE (DFT_sen), .Q (parallel_data[4]));
  SDFFRHQX1 \parallel_data_reg[7] (.RN (n_1), .CK (CLK), .D (n_5), .SI
       (parallel_data[6]), .SE (DFT_sen), .Q (DFT_sdo));
  MX2X1 g176(.A (P_DATA[4]), .B (parallel_data[4]), .S0 (n_0), .Y
       (n_9));
  MX2X1 g177(.A (P_DATA[3]), .B (parallel_data[3]), .S0 (n_0), .Y
       (n_8));
  MX2X1 g178(.A (P_DATA[2]), .B (parallel_data[2]), .S0 (n_0), .Y
       (n_7));
  MX2X1 g179(.A (P_DATA[5]), .B (parallel_data[5]), .S0 (n_0), .Y
       (n_6));
  MX2X1 g180(.A (P_DATA[7]), .B (DFT_sdo), .S0 (n_0), .Y (n_5));
  MX2X1 g181(.A (P_DATA[0]), .B (parallel_data[0]), .S0 (n_0), .Y
       (n_4));
  MX2X1 g182(.A (P_DATA[6]), .B (parallel_data[6]), .S0 (n_0), .Y
       (n_3));
  MX2X1 g183(.A (P_DATA[1]), .B (parallel_data[1]), .S0 (n_0), .Y
       (n_2));
  OR2X1 g184(.A (DFT_in), .B (RST), .Y (n_1));
  NAND2BX1 g185(.AN (busy), .B (Data_Valid), .Y (n_0));
