module UART_TX(P_DATA, Data_Valid, PAR_EN, PAR_TYP, CLK, RST, TX_OUT,
     busy, DFT_in, DFT_sdi, DFT_sen, DFT_sdo);
  input [7:0] P_DATA;
  input Data_Valid, PAR_EN, PAR_TYP, CLK, RST, DFT_in, DFT_sdi, DFT_sen;
  output TX_OUT, busy, DFT_sdo;
