  wire Data_Valid, PAR_EN, PAR_TYP, CLK, RST, DFT_in, DFT_sdi, DFT_sen;
  wire TX_OUT, busy, DFT_sdo;
  wire [1:0] mux_sel;
  wire S_DATA, UNCONNECTED19, n_18, n_19, par_bit, ser_en;
  UART_TX_FSM U0_FSM(.Data_Valid (Data_Valid), .PAR_EN (PAR_EN),
       .ser_done (DFT_sdo), .CLK (CLK), .RST (RST), .ser_en (ser_en),
       .mux_sel ({mux_sel[1], UNCONNECTED19}), .busy (busy), .DFT_in
       (DFT_in), .DFT_sdi (DFT_sdi), .DFT_sen (DFT_sen), .DFT_sdo
       (n_18));
  UART_TX_MUX U0_MUX(.mux_sel ({mux_sel[1], ser_en}), .S_DATA (S_DATA),
       .par_bit (par_bit), .TX_OUT (TX_OUT));
  UART_TX_parity_Calc U0_parity_Calc(.CLK (CLK), .RST (RST), .P_DATA
       (P_DATA), .Data_Valid (Data_Valid), .busy (busy), .PAR_TYP
       (PAR_TYP), .par_bit (par_bit), .DFT_in (DFT_in), .DFT_sdi
       (n_18), .DFT_sen (DFT_sen), .DFT_sdo (n_19));
  UART_TX_serializer U0_serializer(.CLK (CLK), .RST (RST), .Data_Valid
       (Data_Valid), .busy (busy), .P_DATA (P_DATA), .ser_en (ser_en),
       .ser_done (DFT_sdo), .S_DATA (S_DATA), .DFT_in (DFT_in),
       .DFT_sdi (n_19), .DFT_sen (DFT_sen));
endmodule

module UART(TX_CLK, TX_IN_P, TX_IN_V, TX_OUT_S, TX_OUT_V, RST, PAR_TYP,
     PAR_EN, RX_CLK, RX_IN_S, Prescale, RX_OUT_P, RX_OUT_V,
     parity_error, framing_error, DFT_in, DFT_sdi, DFT_sen, DFT_sdo);
  input TX_CLK, TX_IN_V, RST, PAR_TYP, PAR_EN, RX_CLK, RX_IN_S, DFT_in,
       DFT_sdi, DFT_sen;
